import { useState, useEffect } from "react";
import "./Recruitment.css";

/* =========================
   HELPERS
========================= */
const generatePassword = () => {
  const chars =
    "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789@#$!";
  let pass = "";
  for (let i = 0; i < 10; i++) {
    pass += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return pass;
};

const isValidEmail = (email) =>
  /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

const isValidPassword = (password) =>
  /^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&]).{6,}$/.test(password);

function CreateLogin() {
  const [employees, setEmployees] = useState([]);
  const [users, setUsers] = useState([]);

  const [selectedEmp, setSelectedEmp] = useState("");
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [designation, setDesignation] = useState("");

  /* =========================
        LOAD DATA
     ========================= */
  useEffect(() => {
    setEmployees(JSON.parse(localStorage.getItem("employees")) || []);
    setUsers(JSON.parse(localStorage.getItem("users")) || []);
  }, []);

  /* =========================
        SELECT EMPLOYEE
     ========================= */
  const handleSelect = (id) => {
    setSelectedEmp(id);
    setPassword("");

    const emp = employees.find(e => String(e.id) === String(id));
    if (!emp) return;

    setDesignation(emp.designation || "Employee");
    setUsername(emp.email || "");
  };

  /* =========================
        CREATE LOGIN
     ========================= */
  const handleCreate = () => {
    if (!selectedEmp) return alert("Select employee");

    if (!isValidEmail(username))
      return alert("Invalid email format");

    const emp = employees.find(e => String(e.id) === String(selectedEmp));
    if (!emp) return;

    const exists = users.some(u => u.empId === emp.id);
    if (exists)
      return alert("Login already exists for this employee");

    const autoPass = generatePassword();

    const newUser = {
      empId: emp.id,
      name: emp.name,
      username,
      password: autoPass,
      role: "employee"
    };

    const updated = [...users, newUser];
    setUsers(updated);
    localStorage.setItem("users", JSON.stringify(updated));

    alert(
      `Login Created\n\nUsername: ${username}\nPassword: ${autoPass}`
    );
  };

  /* =========================
        RESET PASSWORD
     ========================= */
  const handleReset = (empId) => {
    const newPass = generatePassword();

    if (!isValidPassword(newPass)) {
      alert("Generated password failed validation");
      return;
    }

    const updated = users.map(u =>
      u.empId === empId
        ? { ...u, password: newPass }
        : u
    );

    setUsers(updated);
    localStorage.setItem("users", JSON.stringify(updated));

    alert(
      `Password Reset Successful\n\nNew Password: ${newPass}`
    );
  };

  return (
    <div className="designation-container">
      <h2>Create / Reset Login Credentials</h2>

      <div className="designation-form">
        <select
          value={selectedEmp}
          onChange={(e) => handleSelect(e.target.value)}
        >
          <option value="">Select Employee</option>
          {employees.map(emp => (
            <option key={emp.id} value={emp.id}>
              {emp.name}
            </option>
          ))}
        </select>

        <input
          type="text"
          value={designation}
          disabled
          placeholder="Designation"
        />

        <input
          type="text"
          value={username}
          placeholder="Email / Username"
          onChange={(e) => setUsername(e.target.value)}
        />

        <input
          type="text"
          value={password}
          placeholder="Password will be auto-generated"
          disabled
        />

        <button onClick={handleCreate}>
          Create Login
        </button>
      </div>

      {/* USERS TABLE */}
      <table className="designation-table">
        <thead>
          <tr>
            <th>S.No</th>
            <th>Employee</th>
            <th>Username</th>
            <th>Role</th>
            <th>Action</th>
          </tr>
        </thead>

        <tbody>
          {users.map((u, i) => (
            <tr key={u.empId}>
              <td>{i + 1}</td>
              <td>{u.name}</td>
              <td>{u.username}</td>
              <td>{u.role}</td>
              <td>
                <button onClick={() => handleReset(u.empId)}>
                  Reset Password
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default CreateLogin;
